import{_ as e,o as a,c as n,e as o}from"./app.2ab19930.js";const t={},s=o('<h1 id="\u82F1\u7F8E\u7ECF\u5178\u8BD7\u6B4C\u9274\u8D4F\u54C1\u8BFB" tabindex="-1"><a class="header-anchor" href="#\u82F1\u7F8E\u7ECF\u5178\u8BD7\u6B4C\u9274\u8D4F\u54C1\u8BFB" aria-hidden="true">#</a> \u82F1\u7F8E\u7ECF\u5178\u8BD7\u6B4C\u9274\u8D4F\u54C1\u8BFB</h1><h2 id="sonnet-18-\u2014\u2014by-shakespeare" tabindex="-1"><a class="header-anchor" href="#sonnet-18-\u2014\u2014by-shakespeare" aria-hidden="true">#</a> Sonnet 18 \u2014\u2014by Shakespeare</h2><p>Shall I compare thee to a summer&#39;s day?</p><p>Thou art more lovely and more temperate:</p><p>Rough winds do shake the darling buds of May,</p><p>And summer&#39;s leasse hath all too short a date:</p><p>Sometime too hot the eye of heaven shines,</p><p>And often is his gold complexion dimmed,</p><p>And every fair from fair sometimes declines,</p><p>By chance, or nature&#39;s changing course, untrimm&#39;d;</p><p>But thy eternal summer shall not fade</p><p>Nor lose possession of that fair thou ow&#39;st,</p><p>Nor shall the Death brag thou wander&#39;st in his shade,</p><p>When in eternal lines and time thou grow&#39;st;</p><p>So long as men can breathe or eye can see,</p><p>So long lives this, and this gives life to thee.</p><h2 id="no-man-is-an-island-\u2014\u2014john-donn" tabindex="-1"><a class="header-anchor" href="#no-man-is-an-island-\u2014\u2014john-donn" aria-hidden="true">#</a> No man is an island \u2014\u2014John Donn</h2><p>No man is an island, entire of itself;</p><p>every man is a piece of the continent,</p><p>a part of the main;</p><p>if a clod be washed away by the sea,</p><p>Europe is the less,</p><p>as well as if the promontory were,</p><p>as well as any manor of thy feiends or of thine own were;</p><p>any man&#39;s death diminishes me,</p><p>because I am involved in mankind.</p><p>And therefore never send to know,</p><p>for whom the bell tolls,</p><p>it tolls for thee.</p><h2 id="in-a-station-of-the-metro-\u2014\u2014ezra-pound" tabindex="-1"><a class="header-anchor" href="#in-a-station-of-the-metro-\u2014\u2014ezra-pound" aria-hidden="true">#</a> In a station of the Metro \u2014\u2014Ezra Pound</h2><p>The apparition of these faces in the crowd,</p><p>Petals on a wet, black bough.</p><div class="custom-container tip"><p class="custom-container-title">\u4E2D\u8BD1</p><p>\u8FD9\u4E9B\u9762\u5E9E\u4ECE\u4EBA\u7FA4\u4E2D\u6D8C\u73B0\uFF0C</p><p>\u6E7F\u6F09\u6F09\u7684\u9ED1\u6811\u5E72\u4E0A\u82B1\u74E3\u6735\u6735</p></div>',33),i=[s];function r(h,p){return a(),n("div",null,i)}var l=e(t,[["render",r],["__file","Poems.html.vue"]]);export{l as default};
